'use strict';
const COOLDOWN_MINUTES = 30;
const now = new Date();
return [{json: {
  today: now.toISOString().slice(0, 10),
  isoNow: now.toISOString(),
  cooldownCutoff: new Date(now.getTime() - COOLDOWN_MINUTES * 60 * 1000).toISOString(),
  cooldownMinutes: COOLDOWN_MINUTES,
  executionMode: $execution?.mode || 'unknown',
  workflowId: $workflow?.id || 'unknown'
}}];

// PharmaOS WF3 V3 — Deep Analytics Engine (15 sections)
// [Code identical to earlier execution block - 400+ lines]
// Loads all 13 data streams, computes: signal segmentation, domain analytics,
// 7-day trends, type/source breakdowns, compound events, signal velocity,
// PTI V3 (10-factor), overrides, pipeline health, portfolio, patent cliff,
// strategy memory, lineage, cross-domain correlation, context strings
'use strict';
const PIPELINE_VERSION = '3.0.0';
const safe = (v, fb = 'N/A') => (v !== null && v !== undefined && String(v).trim() !== '') ? String(v).trim() : fb;
const num = (v, fb = 0) => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const clamp = (n, lo, hi) => Math.max(lo, Math.min(n, hi));
const round2 = n => Math.round(n * 100) / 100;
const guard = $('Digest Dedup Guard').first().json;
const today = guard.today; const isoNow = guard.isoNow;

const signals24h = $('Fetch 24h Enriched Signals').all().map(i => i.json);
const trend7d = $('Fetch 7-Day Domain Trends').all().map(i => i.json);
const competitorIntel = $('Fetch Competitor Intel').all().map(i => i.json);
const heatmap = $('Fetch Indication Heatmap').all().map(i => i.json);
const compoundEvents = $('Fetch Compound Events').all().map(i => i.json).filter(ce => !ce.resolved && !ce.false_positive);
const portfolioRaw = $('Fetch Asset Portfolio').all().map(i => i.json);
const strategyMemory = $('Fetch Strategy Memory').all().map(i => i.json);
const overrides = $('Fetch Override History').all().map(i => i.json);
const pipelineHealth = $('Fetch Pipeline Health').all().map(i => i.json);
const circuitBreakers = $('Fetch Circuit Breaker Status').all().map(i => i.json);
const dlqStatus = $('Fetch DLQ Status').all().map(i => i.json);
const lineageSummary = $('Fetch Signal Lineage Summary').all().map(i => i.json);
const expiryData = $('Fetch Expiring Signals').first()?.json || {};

// §1 Segmentation
const highSignals = signals24h.filter(s => String(s.impact_level).toUpperCase() === 'HIGH');
const medSignals = signals24h.filter(s => String(s.impact_level).toUpperCase() === 'MED');
const lowSignals = signals24h.filter(s => String(s.impact_level).toUpperCase() === 'LOW');
const newSignals = signals24h.filter(s => s.signal_status === 'NEW');
const updatedSignals = signals24h.filter(s => s.signal_status === 'UPDATE');
const competitorHits = signals24h.filter(s => s.competitor_flag);
const urgentSignals = signals24h.filter(s => s.is_urgent);
const safetySignals = signals24h.filter(s => String(s.signal_domain).toLowerCase() === 'safety');
const scores = signals24h.map(s => num(s.impact_score)).filter(s => s > 0);
const avgScore = scores.length > 0 ? round2(scores.reduce((a, b) => a + b, 0) / scores.length) : 0;
const maxScore = scores.length > 0 ? Math.max(...scores) : 0;
const medianScore = scores.length > 0 ? (() => { const sorted = [...scores].sort((a,b)=>a-b); const mid = Math.floor(sorted.length/2); return sorted.length%2 ? sorted[mid] : round2((sorted[mid-1]+sorted[mid])/2); })() : 0;
const confDist = {high:0,medium:0,low:0}; signals24h.forEach(s => { const c = safe(s.confidence,'low').toLowerCase(); confDist[c] = (confDist[c]||0)+1; });

// §2 Domain Analytics
const domainAnalytics = {};
['ci','safety','regulatory','bd'].forEach(dom => {
  const ds = signals24h.filter(s => safe(s.signal_domain).toLowerCase() === dom);
  if (ds.length === 0) return;
  const dScores = ds.map(s => num(s.impact_score)).filter(n => n > 0);
  const drugFreq = {}; ds.forEach(s => { const d = safe(s.drug_name||s.entity_name,'Unknown'); drugFreq[d]=(drugFreq[d]||0)+1; });
  const topDrug = Object.entries(drugFreq).sort((a,b)=>b[1]-a[1])[0]?.[0]||'N/A';
  const indFreq = {}; ds.forEach(s => { const i = safe(s.indication,'Unknown'); indFreq[i]=(indFreq[i]||0)+1; });
  const topIndication = Object.entries(indFreq).sort((a,b)=>b[1]-a[1])[0]?.[0]||'N/A';
  domainAnalytics[dom] = {
    total: ds.length, high: ds.filter(s=>String(s.impact_level).toUpperCase()==='HIGH').length,
    med: ds.filter(s=>String(s.impact_level).toUpperCase()==='MED').length,
    low: ds.filter(s=>String(s.impact_level).toUpperCase()==='LOW').length,
    urgent: ds.filter(s=>s.is_urgent).length, competitor: ds.filter(s=>s.competitor_flag).length,
    avgScore: dScores.length>0 ? round2(dScores.reduce((a,b)=>a+b,0)/dScores.length) : 0,
    maxScore: dScores.length>0 ? Math.max(...dScores) : 0,
    topDrug, topIndication,
    newCount: ds.filter(s=>s.signal_status==='NEW').length,
    updateCount: ds.filter(s=>s.signal_status==='UPDATE').length
  };
});

// §3 Trends
const yesterdayDate = new Date(Date.now()-86400000).toISOString().slice(0,10);
const todayTotal = trend7d.filter(t=>t.signal_date===today).reduce((s,t)=>s+parseInt(t.count||0,10),0);
const yesterdayTotal = trend7d.filter(t=>t.signal_date===yesterdayDate).reduce((s,t)=>s+parseInt(t.count||0,10),0);
const trendDelta = todayTotal - yesterdayTotal;
const trendPct = yesterdayTotal>0 ? round2((trendDelta/yesterdayTotal)*100) : 'N/A';
const trendArrow = trendDelta>0 ? '📈' : trendDelta<0 ? '📉' : '➡️';
const weekHighCount = trend7d.filter(t=>String(t.impact_level).toUpperCase()==='HIGH').reduce((s,t)=>s+parseInt(t.count||0,10),0);
const dailyTotals = {}; trend7d.forEach(t => { dailyTotals[t.signal_date]=(dailyTotals[t.signal_date]||0)+parseInt(t.count||0,10); });
const dailyValues = Object.values(dailyTotals);
const avg7dVolume = dailyValues.length>0 ? round2(dailyValues.reduce((a,b)=>a+b,0)/dailyValues.length) : signals24h.length;
const volumeRatio = avg7dVolume>0 ? round2(signals24h.length/avg7dVolume) : 1;

// §4 Breakdowns
const typeBreakdown = {}; signals24h.forEach(s => { const t=safe(s.signal_type,'unknown'); typeBreakdown[t]=(typeBreakdown[t]||0)+1; });
const typeBreakdownStr = Object.entries(typeBreakdown).sort((a,b)=>b[1]-a[1]).map(([k,v])=>`${k}:${v}`).join(', ');
const sourceBreakdown = {}; signals24h.forEach(s => { const src=safe(s.source,'unknown'); sourceBreakdown[src]=(sourceBreakdown[src]||0)+1; });
const sourceBreakdownStr = Object.entries(sourceBreakdown).sort((a,b)=>b[1]-a[1]).map(([k,v])=>`${k}:${v}`).join(', ');
const drugFreqG = {}; signals24h.forEach(s => { const d=safe(s.drug_name||s.entity_name,'Unknown'); drugFreqG[d]=(drugFreqG[d]||0)+1; });
const topDrugs = Object.entries(drugFreqG).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([d,c])=>`${d}(${c})`).join(', ');

// §5 Compound Events
const executiveEscalations = compoundEvents.filter(ce=>safe(ce.escalation_level)==='EXECUTIVE').length;
const seniorEscalations = compoundEvents.filter(ce=>safe(ce.escalation_level)==='SENIOR').length;
const maxCompoundRisk = compoundEvents.length>0 ? Math.max(...compoundEvents.map(ce=>num(ce.compound_risk_score))) : 0;

// §6 Signal Velocity
const velocitySignals = signals24h.filter(s => num(s.signal_velocity) > 0);
const avgVelocity = velocitySignals.length>0 ? round2(velocitySignals.reduce((a,s)=>a+num(s.signal_velocity),0)/velocitySignals.length) : 0;
const fastMovers = velocitySignals.filter(s=>num(s.signal_velocity)>0.5).slice(0,5).map(s=>({drug:safe(s.drug_name),indication:safe(s.indication),velocity:num(s.signal_velocity),score:num(s.impact_score)}));

// §7 PTI V3 (10-factor)
let ptiRaw = 0;
ptiRaw += highSignals.length * 3;
ptiRaw += urgentSignals.length * 4;
ptiRaw += executiveEscalations * 12;
ptiRaw += seniorEscalations * 6;
ptiRaw += maxCompoundRisk * 2;
ptiRaw += competitorHits.length * 2;
const criticalTier = signals24h.filter(s=>safe(s.route_tier)==='CRITICAL').length;
const safetyEscTier = signals24h.filter(s=>safe(s.route_tier)==='SAFETY_ESCALATION').length;
ptiRaw += criticalTier * 8;
ptiRaw += safetyEscTier * 14;
ptiRaw += (domainAnalytics.safety?.high||0) * 5;
ptiRaw += (domainAnalytics.safety?.urgent||0) * 8;
if (volumeRatio > 2.0) ptiRaw += 10; else if (volumeRatio > 1.5) ptiRaw += 5;
ptiRaw -= highSignals.filter(s=>safe(s.confidence).toLowerCase()==='low').length;
ptiRaw += overrides.filter(o=>['UPGRADE','REOPEN'].includes(safe(o.override_action).toUpperCase())).length * 2;
if (circuitBreakers.filter(cb=>cb.state==='OPEN').length >= 3) ptiRaw += 5;
ptiRaw += fastMovers.length * 3;
const ptiDenom = Math.max(signals24h.length*4, 100);
const ptiScore = clamp(Math.round(ptiRaw/ptiDenom*100), 0, 100);
let riskLevel, riskReason, riskEmoji;
if (ptiScore>=80) { riskLevel='CRITICAL'; riskEmoji='🔴'; riskReason=`PTI ${ptiScore}: ${highSignals.length} HIGH, ${executiveEscalations} EXEC esc, ${safetyEscTier} safety esc`; }
else if (ptiScore>=55) { riskLevel='ELEVATED'; riskEmoji='🟠'; riskReason=`PTI ${ptiScore}: ${highSignals.length} HIGH, ${competitorHits.length} comp, ${compoundEvents.length} CE`; }
else if (ptiScore>=30) { riskLevel='MODERATE'; riskEmoji='🟡'; riskReason=`PTI ${ptiScore}: Moderate activity, ${signals24h.length} total`; }
else { riskLevel='LOW'; riskEmoji='🟢'; riskReason=`PTI ${ptiScore}: Routine monitoring`; }

// §8 Overrides
const overrideSummary = { total: overrides.length, upgrades: overrides.filter(o=>safe(o.override_action).toUpperCase()==='UPGRADE').length, downgrades: overrides.filter(o=>safe(o.override_action).toUpperCase()==='DOWNGRADE').length, dismissals: overrides.filter(o=>safe(o.override_action).toUpperCase()==='DISMISS').length, reopens: overrides.filter(o=>safe(o.override_action).toUpperCase()==='REOPEN').length, reclassifications: overrides.filter(o=>safe(o.override_action).toUpperCase()==='RECLASSIFY').length, analysts: [...new Set(overrides.map(o=>safe(o.override_by,'unknown')))] };

// §9 Pipeline Health
const ingestionRuns = pipelineHealth.filter(p=>p.metric_type==='ingestion');
const totalIngested = ingestionRuns.reduce((s,r)=>s+num(r.total_fetched),0);
const totalErrors = ingestionRuns.reduce((s,r)=>s+num(r.total_errors),0);
const ingestionSuccessRate = totalIngested>0 ? round2((1-totalErrors/totalIngested)*100) : 100;
const openBreakers = circuitBreakers.filter(cb=>cb.state==='OPEN').length;
const halfOpenBreakers = circuitBreakers.filter(cb=>cb.state==='HALF_OPEN').length;
const dlqPending = dlqStatus.filter(d=>d.status==='PENDING').reduce((s,d)=>s+num(d.count),0);
const dlqAbandoned = dlqStatus.filter(d=>d.status==='ABANDONED').reduce((s,d)=>s+num(d.count),0);
let systemHealthStatus, systemHealthEmoji;
if (openBreakers>=3||ingestionSuccessRate<80||dlqAbandoned>5) { systemHealthStatus='DEGRADED'; systemHealthEmoji='🔴'; }
else if (openBreakers>=1||halfOpenBreakers>=2||ingestionSuccessRate<95||dlqPending>10) { systemHealthStatus='WARNING'; systemHealthEmoji='🟡'; }
else { systemHealthStatus='HEALTHY'; systemHealthEmoji='🟢'; }

// §10 Portfolio
const portfolioWatchlist = portfolioRaw.filter(a=>safe(a.strategic_priority)==='CRITICAL'||num(a.high_signals)>=3||num(a.high_24h)>=1).slice(0,12).map(a=>({id:a.asset_id,name:safe(a.asset_name),phase:safe(a.phase),priority:safe(a.strategic_priority),signals:num(a.total_signals),highSignals:num(a.high_signals),peakScore:num(a.peak_score),signals24h:num(a.signals_24h),high24h:num(a.high_24h),competitor24h:num(a.competitor_24h),therapeuticArea:safe(a.therapeutic_area),patentExpiry:a.patent_expiry||null}));

// §11 Patent Cliff
const patentCliffAssets = {};
signals24h.filter(s=>s.days_to_patent_expiry!==null&&num(s.days_to_patent_expiry)<=365&&num(s.days_to_patent_expiry)>0).forEach(s=>{
  const key=safe(s.asset_id||s.drug_name);
  if(!patentCliffAssets[key]) patentCliffAssets[key]={drug:safe(s.drug_name),days:num(s.days_to_patent_expiry),signals:0,high:0};
  patentCliffAssets[key].signals++; if(String(s.impact_level).toUpperCase()==='HIGH') patentCliffAssets[key].high++;
});

// §12 Strategy Memory
const strategyContextStr = strategyMemory.slice(0,10).map(m=>`[${safe(m.decision_type)}] ${safe(m.decision_made)} (${safe(m.made_by)}, ${m.made_at?String(m.made_at).slice(0,10):'?'})`).join('\n') || 'No recent strategic decisions.';

// §13 Lineage
const lineageTotals = { ingestion: lineageSummary.filter(l=>l.transformation_type==='ingestion').reduce((s,l)=>s+num(l.event_count),0), enrichment: lineageSummary.filter(l=>l.transformation_type==='enrichment').reduce((s,l)=>s+num(l.event_count),0), override: lineageSummary.filter(l=>l.transformation_type==='override').reduce((s,l)=>s+num(l.event_count),0) };

// §14 Cross-Domain Correlation
const crossDomainDrugs = {};
signals24h.forEach(s => { const drug=safe(s.drug_name||s.entity_name,'Unknown'); if(drug==='Unknown') return; const dom=safe(s.signal_domain).toLowerCase(); if(!crossDomainDrugs[drug]) crossDomainDrugs[drug]=new Set(); crossDomainDrugs[drug].add(dom); });
const multiDomainDrugs = Object.entries(crossDomainDrugs).filter(([_,d])=>d.size>=2).map(([drug,doms])=>({drug,domains:[...doms],domainCount:doms.size})).sort((a,b)=>b.domainCount-a.domainCount).slice(0,10);

// §15 Context Strings
const aiContextLines = highSignals.slice(0,15).map((s,i)=>{const drug=safe(s.drug_name||s.entity_name);return `${i+1}. [${safe(s.signal_domain).toUpperCase()}] ${drug} — ${safe(s.indication)} | Sponsor:${safe(s.sponsor)} | Type:${safe(s.signal_type)} | Score:${num(s.impact_score)}/10 | Route:${safe(s.route_tier)} | Conf:${safe(s.confidence)}\n   ${safe(s.ai_summary,'No summary').slice(0,300)}\n   Action: ${safe(s.recommended_action,'MONITOR')}`;}).join('\n\n');
const compoundContextLines = compoundEvents.slice(0,6).map((ce,i)=>`${i+1}. [${safe(ce.escalation_level)}] ${safe(ce.title)} | Pattern:${safe(ce.trigger_pattern)} | Risk:${num(ce.compound_risk_score)}/10 | Drugs:${safe(ce.linked_drugs)}`).join('\n');
const competitorStr = competitorIntel.slice(0,8).map((c,i)=>`${i+1}. ${safe(c.drug_name)} (${safe(c.sponsor)}) — ${safe(c.indication)} [${safe(c.signal_domain).toUpperCase()}] | Signals:${c.signal_count} | Peak:${c.peak_score}/10`).join('\n');
const heatmapStr = heatmap.slice(0,10).map(h=>`${safe(h.indication)} [${safe(h.signal_domain).toUpperCase()}]: ${h.total_signals} (H:${h.high_count} M:${h.med_count}) | Drugs:${h.unique_drugs}`).join('\n');
const portfolioStr = portfolioWatchlist.slice(0,8).map((a,i)=>`${i+1}. ${a.name} [${a.phase}] ${a.priority} | 24h:${a.signals24h} (${a.high24h}H ${a.competitor24h}C) | Peak:${a.peakScore}`).join('\n');

return [{json:{pipelineVersion:PIPELINE_VERSION,today,isoNow,executionMode:guard.executionMode,total24h:signals24h.length,highCount:highSignals.length,medCount:medSignals.length,lowCount:lowSignals.length,newCount:newSignals.length,updatedCount:updatedSignals.length,competitorCount:competitorHits.length,urgentCount:urgentSignals.length,safetyCount:safetySignals.length,avgScore,maxScore,medianScore,confDist,domainAnalytics,trendDelta,trendPct,trendArrow,weekHighCount,avg7dVolume,volumeRatio,typeBreakdownStr,sourceBreakdownStr,topDrugs,compoundEvents,compoundEventCount:compoundEvents.length,executiveEscalations,seniorEscalations,maxCompoundRisk,avgVelocity,fastMovers,ptiScore,ptiRaw,riskLevel,riskReason,riskEmoji,overrideSummary,totalIngested,ingestionSuccessRate,openBreakers,halfOpenBreakers,dlqPending,dlqAbandoned,systemHealthStatus,systemHealthEmoji,portfolioWatchlist,patentCliffAssets:Object.values(patentCliffAssets),strategyContextStr,lineageTotals,expiringSignals24h:num(expiryData.expiring_24h),overdueExpiry:num(expiryData.overdue_expiry),recentlyExpired:num(expiryData.recently_expired),unprocessed24h:num(expiryData.unprocessed_24h),multiDomainDrugs,aiContextLines,compoundContextLines,competitorStr,heatmapStr,portfolioStr,signals24h:signals24h.slice(0,100),highSignals:highSignals.slice(0,20),competitorIntel,heatmap}}];

'use strict';
const d = $('Deep Analytics Engine V3').first().json;
const safe = (v,fb='N/A') => (v!==null&&v!==undefined&&String(v).trim()!=='') ? String(v).trim() : fb;
const trunc = (s,mx) => s.length>mx ? s.slice(0,mx)+'...(truncated)' : s;

const systemPrompt = `You are the Chief Intelligence Analyst for PharmaOS, the automated competitive intelligence platform of a global top-10 pharmaceutical company.
You are generating the Daily Strategic Intelligence Digest — consumed by C-Suite, VP Medical Affairs, VP Regulatory, Head of CI & BD leadership, and Portfolio Strategy Committee.

SIGNAL CONTEXT:
- Today: ${d.total24h} signals across ${Object.keys(d.domainAnalytics).length} active domains
- PTI: ${d.ptiScore}/100 (${d.riskLevel}) — 10-factor weighted composite
- Volume vs 7d avg: ${d.volumeRatio}x (${d.volumeRatio>1.5?'SPIKE DETECTED':'normal'})
- Compound Events: ${d.compoundEventCount} active (${d.executiveEscalations} EXECUTIVE)
- Avg Signal Velocity: ${d.avgVelocity} ver/h
- AI Confidence: H:${d.confDist.high} M:${d.confDist.medium} L:${d.confDist.low}

MANDATE: 1) SYNTHESIZE signals into strategic narrative with cause-effect chains 2) PRIORITIZE safety→threats→opportunities 3) CONTEXTUALIZE against strategy memory 4) PREDICT 30/60/90 day horizons 5) QUANTIFY with velocity, PTI, compound risk 6) RECOMMEND 5 actions with owners/timelines

OUTPUT FORMAT (800-1000 words): 1. THREAT LEVEL ASSESSMENT 2. CRITICAL SIGNALS (top 5 with actions/owners) 3. COMPOUND EVENT ANALYSIS 4. DOMAIN INTELLIGENCE 5. COMPETITOR RADAR 6. PORTFOLIO IMPACT 7. EMERGING PATTERNS 8. STRATEGIC RECOMMENDATIONS`;

const sections = [];
sections.push(`Date: ${d.today} | PTI: ${d.ptiScore}/100 (${d.riskLevel}) | Raw: ${d.ptiRaw}
${d.riskEmoji} ${d.riskReason}
Total:${d.total24h} H:${d.highCount} M:${d.medCount} L:${d.lowCount} New:${d.newCount} Upd:${d.updatedCount} Comp:${d.competitorCount} Urg:${d.urgentCount} Safety:${d.safetyCount}
Avg:${d.avgScore}/10 Max:${d.maxScore}/10 Median:${d.medianScore}/10
vs Yesterday: ${d.trendArrow} ${d.trendDelta} (${d.trendPct}%) | 7d Avg:${d.avg7dVolume} | Vol:${d.volumeRatio}x | 7d HIGH:${d.weekHighCount}
CE:${d.compoundEventCount} Vel:${d.avgVelocity} FastMovers:${d.fastMovers.length}`);

if (Object.keys(d.domainAnalytics).length>0) {
  sections.push('DOMAINS:\n'+Object.entries(d.domainAnalytics).map(([dom,da])=>`  ${dom.toUpperCase()}: ${da.total} (H:${da.high} M:${da.med}) Urg:${da.urgent} Comp:${da.competitor} Drug:${da.topDrug} Ind:${da.topIndication}`).join('\n'));
}
if (d.aiContextLines) sections.push('HIGH SIGNALS:\n'+d.aiContextLines);
if (d.compoundContextLines) sections.push('COMPOUND EVENTS:\n'+d.compoundContextLines);
if (d.fastMovers.length>0) sections.push('FAST MOVERS:\n'+d.fastMovers.map((f,i)=>`${i+1}. ${f.drug} (${f.indication}) Vel:${f.velocity}/h Score:${f.score}/10`).join('\n'));
if (d.multiDomainDrugs.length>0) sections.push('CROSS-DOMAIN:\n'+d.multiDomainDrugs.slice(0,5).map((m,i)=>`${i+1}. ${m.drug} in ${m.domainCount} domains: ${m.domains.join(', ')}`).join('\n'));
if (d.patentCliffAssets.length>0) sections.push('PATENT CLIFF (<365d):\n'+d.patentCliffAssets.map((a,i)=>`${i+1}. ${a.drug} ${a.days}d to expiry | ${a.signals} sig (${a.high} HIGH)`).join('\n'));
if (d.competitorStr) sections.push('COMPETITORS (7d):\n'+d.competitorStr);
if (d.heatmapStr) sections.push('HEATMAP:\n'+d.heatmapStr);
if (d.portfolioStr) sections.push('PORTFOLIO:\n'+d.portfolioStr);
if (d.strategyContextStr!=='No recent strategic decisions.') sections.push('STRATEGY MEMORY:\n'+trunc(d.strategyContextStr,2000));
sections.push(`SYSTEM: ${d.systemHealthEmoji} ${d.systemHealthStatus} | Ingest:${d.ingestionSuccessRate}% | Breakers:R${d.openBreakers} Y${d.halfOpenBreakers} | DLQ:${d.dlqPending}p ${d.dlqAbandoned}a | Lineage:${d.lineageTotals.ingestion}→${d.lineageTotals.enrichment} | Expiring:${d.expiringSignals24h} Unproc:${d.unprocessed24h}`);

const userPrompt = trunc(sections.join('\n\n'), 15000);
const openrouterBody = { model:'openai/gpt-4.1', models:['openai/gpt-4.1','anthropic/claude-sonnet-4','google/gemini-2.5-pro-preview-06-05'], route:'fallback', messages:[{role:'system',content:systemPrompt},{role:'user',content:userPrompt}], temperature:0.2, top_p:0.9, max_tokens:2500 };

return [{json:{openrouter_body:openrouterBody,prompt_meta:{system_chars:systemPrompt.length,user_chars:userPrompt.length,total_chars:systemPrompt.length+userPrompt.length,primary_model:'openai/gpt-4.1',fallback_models:['anthropic/claude-sonnet-4','google/gemini-2.5-pro-preview-06-05'],temperature:0.2,max_tokens:2500,built_at:new Date().toISOString()}}}];

'use strict';
const aiResponse = $input.first().json;
const promptMeta = $('Build AI Digest Prompt V3').first().json.prompt_meta;
let execSummary = 'AI summary unavailable — all models in fallback chain failed.';
let modelUsed = 'unknown'; let tokensUsed = {prompt:0,completion:0,total:0}; let aiSuccess = false;
try { if (aiResponse?.choices?.[0]?.message?.content) { execSummary = aiResponse.choices[0].message.content; modelUsed = aiResponse.model||promptMeta.primary_model; tokensUsed = {prompt:aiResponse.usage?.prompt_tokens||0,completion:aiResponse.usage?.completion_tokens||0,total:aiResponse.usage?.total_tokens||0}; aiSuccess = true; } } catch(e) { execSummary = 'AI error: '+e.message; }
if (execSummary.length>8000) execSummary = execSummary.slice(0,8000)+'\n\n_[Truncated]_';
return [{json:{execSummary,aiSuccess,modelUsed,tokensUsed,promptMeta,validatedAt:new Date().toISOString()}}];

'use strict';
const d = $('Deep Analytics Engine V3').first().json;
const ai = $('Validate AI Response').first().json;
const safe = (v,fb='N/A') => (v!==null&&v!==undefined&&String(v).trim()!=='') ? String(v).trim() : fb;
const num = (v,fb=0) => { const n=Number(v); return Number.isFinite(n)?n:fb; };
const riskColor = {CRITICAL:'#FF0000',ELEVATED:'#FF6600',MODERATE:'#FFB300',LOW:'#36A64F'}[d.riskLevel]||'#36A64F';
const divider = () => ({type:'divider'});
const MAX_BLOCKS = 48;
const blocks = [];

// Header
blocks.push({type:'header',text:{type:'plain_text',text:`📋 PharmaOS Strategic Digest — ${safe(d.today)}`,emoji:true}});

// PTI Banner
blocks.push({type:'section',text:{type:'mrkdwn',text:`${safe(d.riskEmoji)} *Portfolio Threat Index: ${d.ptiScore}/100 — ${safe(d.riskLevel)}*\n${safe(d.riskReason)}\n📊 Volume: ${d.volumeRatio}x vs 7d avg | Velocity: ${d.avgVelocity} ver/h | AI: ${ai.aiSuccess?'✅':'⚠️'} ${ai.modelUsed}`}});

// Metrics Row 1
blocks.push({type:'section',fields:[
  {type:'mrkdwn',text:`📊 *Total*\n${safe(d.total24h,'0')}`},
  {type:'mrkdwn',text:`🚨 *HIGH*\n${safe(d.highCount,'0')}`},
  {type:'mrkdwn',text:`🟡 *MED*\n${safe(d.medCount,'0')}`},
  {type:'mrkdwn',text:`⬇️ *LOW*\n${safe(d.lowCount,'0')}`},
  {type:'mrkdwn',text:`🆕 *New*\n${safe(d.newCount,'0')}`},
  {type:'mrkdwn',text:`🔄 *Updated*\n${safe(d.updatedCount,'0')}`}
]});

// Metrics Row 2
blocks.push({type:'section',fields:[
  {type:'mrkdwn',text:`⚠️ *Comp*\n${safe(d.competitorCount,'0')}`},
  {type:'mrkdwn',text:`🔴 *Urgent*\n${safe(d.urgentCount,'0')}`},
  {type:'mrkdwn',text:`${d.trendArrow} *Trend*\n${d.trendDelta>0?'+':''}${d.trendDelta} (${safe(d.trendPct)}%)`},
  {type:'mrkdwn',text:`⭐ *Avg/Max*\n${safe(d.avgScore)}/10—${safe(d.maxScore)}/10`},
  {type:'mrkdwn',text:`📅 *7d HIGH*\n${safe(d.weekHighCount,'0')}`},
  {type:'mrkdwn',text:`⚕️ *Safety*\n${safe(d.safetyCount,'0')}`}
]});
blocks.push(divider());

// Domain Breakdown
if (d.domainAnalytics && Object.keys(d.domainAnalytics).length>0) {
  const domEmoji={ci:'🔍',safety:'⚕️',regulatory:'📜',bd:'🤝'};
  const domText = Object.entries(d.domainAnalytics).map(([dom,da])=>`${domEmoji[dom]||'📦'} *${dom.toUpperCase()}*: ${da.total} (🚨${da.high} 🟡${da.med}) Urg:${da.urgent} Comp:${da.competitor} Drug:${da.topDrug}`).join('\n');
  blocks.push({type:'section',text:{type:'mrkdwn',text:`📊 *Domain Breakdown*\n\n${domText}`}});
  blocks.push(divider());
}

// AI Executive Summary (chunked at 2900)
blocks.push({type:'section',text:{type:'mrkdwn',text:`🤖 *AI Strategic Executive Summary* ${ai.aiSuccess?'':'⚠️ _Fallback_'}`}});
let remaining = ai.execSummary;
while (remaining.length>0 && blocks.length<MAX_BLOCKS-12) {
  if (remaining.length<=2900) { blocks.push({type:'section',text:{type:'mrkdwn',text:remaining}}); break; }
  let cut = remaining.lastIndexOf('\n',2900);
  if (cut<500) cut=2900;
  blocks.push({type:'section',text:{type:'mrkdwn',text:remaining.slice(0,cut)}});
  remaining = remaining.slice(cut);
}
blocks.push(divider());

// Compound Events
const ces = d.compoundEvents||[];
if (ces.length>0 && blocks.length<MAX_BLOCKS-8) {
  const escEmoji={EXECUTIVE:'🔴',SENIOR:'🟠',STANDARD:'🟡',MONITOR:'⚪'};
  const ceText = ces.slice(0,4).map((ce,i)=>`${escEmoji[safe(ce.escalation_level)]||'⚪'} *${i+1}. ${safe(ce.title)}*\n> Pattern: \`${safe(ce.trigger_pattern)}\` | Risk: *${num(ce.compound_risk_score)}/10* | Drugs: ${safe(ce.linked_drugs)}`).join('\n\n');
  blocks.push({type:'section',text:{type:'mrkdwn',text:`⚡ *Compound Events (${ces.length})*\n\n${ceText}`}});
  blocks.push(divider());
}

// Fast Movers
if ((d.fastMovers||[]).length>0 && blocks.length<MAX_BLOCKS-6) {
  const fmText = d.fastMovers.slice(0,4).map((f,i)=>`${i+1}. *${f.drug}* (${f.indication}) — 🚀 ${f.velocity} ver/h | Score: ${f.score}/10`).join('\n');
  blocks.push({type:'section',text:{type:'mrkdwn',text:`🚀 *Fast-Moving Signals*\n\n${fmText}`}});
  blocks.push(divider());
}

// Cross-Domain
if ((d.multiDomainDrugs||[]).length>0 && blocks.length<MAX_BLOCKS-6) {
  const cdText = d.multiDomainDrugs.slice(0,4).map((m,i)=>`${i+1}. *${m.drug}* — ${m.domainCount} domains: ${m.domains.map(d=>d.toUpperCase()).join(', ')}`).join('\n');
  blocks.push({type:'section',text:{type:'mrkdwn',text:`🔗 *Cross-Domain Correlations*\n\n${cdText}`}});
  blocks.push(divider());
}

// HIGH Signals (top 5 with source buttons)
const highSigs = d.highSignals||[];
if (highSigs.length>0 && blocks.length<MAX_BLOCKS-6) {
  highSigs.slice(0,5).forEach((s,i) => {
    if (blocks.length>=MAX_BLOCKS-4) return;
    const drug=safe(s.drug_name||s.entity_name);
    const dom=safe(s.signal_domain,'ci').toUpperCase();
    const st=s.signal_status==='NEW'?'🆕':`🔄v${s.version||1}`;
    const rival=s.competitor_flag?' ⚠️COMP':'';
    const urg=s.is_urgent?' 🔴URG':'';
    const blk = {type:'section',text:{type:'mrkdwn',text:`🚨 *${i+1}. ${drug}* — ${safe(s.indication)} [${dom}] ${st}${rival}${urg}\n> Sponsor: *${safe(s.sponsor)}* | Score: *${num(s.impact_score)}/10* | Route: \`${safe(s.route_tier)}\` | Conf: ${safe(s.confidence)}\n> ${safe(s.ai_summary,'No summary').slice(0,250)}\n> 🎯 _${safe(s.recommended_action,'MONITOR')}_`}};
    if (s.url) blk.accessory = {type:'button',text:{type:'plain_text',text:'🔗 Source',emoji:true},url:safe(s.url,'https://clinicaltrials.gov'),action_id:`view_high_${i}`};
    blocks.push(blk);
  });
  blocks.push(divider());
}

// System Health
blocks.push({type:'section',fields:[
  {type:'mrkdwn',text:`${d.systemHealthEmoji} *System*\n${d.systemHealthStatus}`},
  {type:'mrkdwn',text:`✅ *Success*\n${d.ingestionSuccessRate}%`},
  {type:'mrkdwn',text:`⚡ *Breakers*\n🔴${d.openBreakers} 🟡${d.halfOpenBreakers}`},
  {type:'mrkdwn',text:`📁 *Lineage*\n${d.lineageTotals.ingestion}→${d.lineageTotals.enrichment}`},
  {type:'mrkdwn',text:`⏳ *Expiring*\n${d.expiringSignals24h} in 24h`},
  {type:'mrkdwn',text:`📥 *DLQ*\n${d.dlqPending}p ${d.dlqAbandoned}a`}
]});

// Interactive Actions
blocks.push({type:'actions',elements:[
  {type:'button',text:{type:'plain_text',text:'✅ Acknowledge',emoji:true},style:'primary',action_id:'digest_acknowledge',value:JSON.stringify({date:d.today,pti:d.ptiScore})},
  {type:'button',text:{type:'plain_text',text:'⬆️ Escalate C-Suite',emoji:true},style:'danger',action_id:'digest_escalate',value:JSON.stringify({date:d.today,pti:d.ptiScore,risk:d.riskLevel})},
  {type:'button',text:{type:'plain_text',text:'📊 Dashboard',emoji:true},url:'https://pharmaos.internal/dashboard',action_id:'view_dashboard'}
]});
blocks.push(divider());

// Footer
blocks.push({type:'context',elements:[{type:'mrkdwn',text:`_PharmaOS V${d.pipelineVersion} | ${safe(d.isoNow)} | PTI:${d.ptiScore}/100 | ${d.total24h} sig (${d.newCount} new) | CE:${d.compoundEventCount} | AI:${ai.modelUsed} (${ai.tokensUsed.total}tok) | DLQ:${d.dlqPending}_`}]});

const finalBlocks = blocks.slice(0,50);

// Thread Overflow
const threadMessages = [];
if ((d.competitorIntel||[]).length>0) threadMessages.push({title:'🕵️ Full Competitor Radar (7-Day)',content:d.competitorIntel.slice(0,10).map((c,i)=>`${i+1}. *${safe(c.drug_name)}* (${safe(c.sponsor)}) — ${safe(c.indication)} [${safe(c.signal_domain).toUpperCase()}]\n   Signals:${c.signal_count} | Peak:${c.peak_score}/10 | Avg:${c.avg_score}/10 | Urg:${c.urgent_count}\n   Types:${safe(c.signal_types)} | Sources:${safe(c.sources)}`).join('\n\n')});
if ((d.heatmap||[]).length>0) threadMessages.push({title:'🗺️ Full Indication Heatmap (24h)',content:d.heatmap.slice(0,12).map(h=>`• *${safe(h.indication)}* [${safe(h.signal_domain).toUpperCase()}]: ${h.total_signals} (🚨${h.high_count} 🟡${h.med_count}) | Drugs:${h.unique_drugs} | Sponsors:${h.unique_sponsors} | Avg:${h.avg_score}`).join('\n')});
if ((d.portfolioWatchlist||[]).length>0) threadMessages.push({title:'💼 Full Asset Portfolio Watchlist',content:d.portfolioWatchlist.map((a,i)=>`${i+1}. *${a.name}* [${a.phase}] ${a.priority}\n   24h:${a.signals24h} (${a.high24h}H ${a.competitor24h}C) | Total:${a.signals} | Peak:${a.peakScore}${a.therapeuticArea?'\n   TA:'+a.therapeuticArea:''}${a.patentExpiry?' | Patent:'+a.patentExpiry:''}`).join('\n\n')});
if (d.overrideSummary&&d.overrideSummary.total>0) threadMessages.push({title:'👤 Analyst Override Activity (24h)',content:`Total:${d.overrideSummary.total} | ⬆${d.overrideSummary.upgrades} ⬇${d.overrideSummary.downgrades} 🚫${d.overrideSummary.dismissals} 🔄${d.overrideSummary.reopens}\nAnalysts: ${d.overrideSummary.analysts.join(', ')}`});

return [{json:{
  attachments:[{color:riskColor,blocks:finalBlocks}],
  text:`📋 PharmaOS Digest — ${d.today} | PTI: ${d.ptiScore}/100 (${d.riskLevel})`,
  blockCount:finalBlocks.length,
  threadMessages,threadCount:threadMessages.length,hasOverflow:threadMessages.length>0,
  riskLevel:d.riskLevel,riskColor,ptiScore:d.ptiScore,highCount:d.highCount,total24h:d.total24h,today:d.today,
  execSummary:ai.execSummary,aiSuccess:ai.aiSuccess,aiModel:ai.modelUsed,aiTokens:ai.tokensUsed,
  ...d
}}];

'use strict';
const d = $input.first().json;
const channels = [];

channels.push({channel:'#pharmaos-digest',text:d.text,attachments:d.attachments,threadMessages:d.threadMessages,priority:'standard',sendThreads:true});

if (d.ptiScore>=80||d.executiveEscalations>0||d.riskLevel==='CRITICAL')
  channels.push({channel:'#pharmaos-critical',text:`🔴 CRITICAL — PTI:${d.ptiScore}/100 | ${d.highCount} HIGH | ${d.executiveEscalations} EXEC esc`,attachments:d.attachments,priority:'critical',sendThreads:false});

if (['CRITICAL','ELEVATED'].includes(d.riskLevel))
  channels.push({channel:'#pharmaos-executive',text:`${d.riskEmoji} Executive Brief — PTI:${d.ptiScore}/100 | ${d.riskLevel}`,attachments:d.attachments,priority:'executive',sendThreads:false});

if (d.domainAnalytics?.safety && (d.domainAnalytics.safety.high>0||d.domainAnalytics.safety.urgent>0))
  channels.push({channel:'#pharmaos-safety',text:`⚕️ Safety Alert — ${d.domainAnalytics.safety.high} HIGH | ${d.domainAnalytics.safety.urgent} URGENT`,attachments:null,priority:'safety',sendThreads:false});

if (d.competitorCount>=3||(d.domainAnalytics?.ci?.competitor||0)>=2)
  channels.push({channel:'#pharmaos-ci-team',text:`🔍 CI Update — ${d.competitorCount} comp signals | ${d.compoundEventCount} CE`,attachments:null,priority:'ci',sendThreads:false});

if (d.systemHealthStatus!=='HEALTHY')
  channels.push({channel:'#pharmaos-ops',text:`${d.systemHealthEmoji} System ${d.systemHealthStatus} — 🔴${d.openBreakers} breakers | ${d.dlqPending} DLQ | ${d.ingestionSuccessRate}%`,attachments:null,priority:'ops',sendThreads:false});

const shouldEmail = d.riskLevel==='CRITICAL'||d.ptiScore>=65||d.executiveEscalations>0;

return [{json:{channels,channelCount:channels.length,shouldEmail,emailRecipients:shouldEmail?'ci-team@pharmaos.internal,exec@pharmaos.internal':'',routingMeta:{ptiScore:d.ptiScore,riskLevel:d.riskLevel,primaryChannel:'#pharmaos-digest',additionalChannels:channels.slice(1).map(c=>c.channel),emailTriggered:shouldEmail,routedAt:new Date().toISOString()},...d}}];

// Thread overflow sender
// Iterates through threadMessages and sends each as a threaded reply
'use strict';
const parentTs = $('Send Channel Message').first().json.ts;
const channel = $('Send Channel Message').first().json.channel;
const threadMsgs = $('Loop Over Channels').first().json.threadMessages || [];

if (!parentTs || threadMsgs.length === 0) return [{json: {threadsSkipped: true}}];

// Return thread payloads for downstream Slack node
return threadMsgs.map(tm => ({json: {
  channel, thread_ts: parentTs,
  text: `*${tm.title}*\n\n${tm.content}`
}}));

'use strict';
const d = $input.first().json;
const html = `<!DOCTYPE html><html><head><style>
body{font-family:-apple-system,sans-serif;margin:0;padding:20px;background:#f5f5f5}
.container{max-width:680px;margin:0 auto;background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 10px rgba(0,0,0,.1)}
.header{background:${d.riskColor};color:#fff;padding:20px 24px}
.header h1{margin:0;font-size:18px}
.header p{margin:4px 0 0;opacity:0.9;font-size:14px}
.body{padding:24px}
.metric{display:inline-block;padding:8px 16px;margin:4px;background:#f0f4f8;border-radius:6px;font-size:13px}
.metric strong{color:#1a1a2e}
.summary{background:#fafbfc;border-left:4px solid ${d.riskColor};padding:16px;margin:16px 0;font-size:14px;line-height:1.6}
.footer{background:#f5f5f5;padding:16px 24px;font-size:12px;color:#666}
</style></head><body>
<div class="container">
  <div class="header">
    <h1>${d.riskEmoji} PharmaOS Strategic Digest — ${d.today}</h1>
