  </div>
  <div class="body">
    <div class="metric"><strong>HIGH:</strong> ${d.highCount}</div>
    <div class="metric"><strong>MED:</strong> ${d.medCount}</div>
    <div class="metric"><strong>Competitor:</strong> ${d.competitorCount}</div>
    <div class="metric"><strong>Urgent:</strong> ${d.urgentCount}</div>
    <div class="metric"><strong>Compound Events:</strong> ${d.compoundEventCount}</div>
    <div class="metric"><strong>AI Model:</strong> ${d.aiModel}</div>
    <div class="summary">${(d.execSummary||'').replace(/\n/g,'<br>')}</div>
  </div>
  <div class="footer">PharmaOS V${d.pipelineVersion} | Generated ${d.isoNow} | ${d.channelCount} Slack channels | AI: ${d.aiTokens?.total||0} tokens</div>
