</body></html>`;
return [{json:{html,subject:`${d.riskEmoji} PharmaOS Digest ${d.today} — PTI ${d.ptiScore}/100 (${d.riskLevel})`,recipients:d.emailRecipients}}];

// Ensure Multi-Channel Router V3 always returns channels array
const data = $input.first().json;
return [{
  json: {
    ...data,
    channels: Array.isArray(data.channels) ? data.channels : [],
    channelCount: data.channels?.length || 0
  }
}];
